import axios from "axios";

// Use environment variable or fallback
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// Axios interceptor to add JWT token to protected requests
api.interceptors.request.use((config) => {
  const token =
    localStorage.getItem("nfxtoken") || sessionStorage.getItem("nfxtoken");

  // 👉 Skip attaching token for login/signup requests
  if (token && !config.url.includes("/auth/")) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  return config;
});

// Signup
export const signup = async (email, password) => {
  return api.post("/auth/signup", { email, password });
};

// Login - unwrap data here
export const login = async (email, password) => {
  const response = await api.post("/auth/login", { email, password });
  return response.data; // Return only data to caller
};

// Example of authorized request (after login)
export const getProtectedData = async () => {
  return api.get("/protected"); // interceptor will add token
};

export default api;
